424		private calculateSeasonalComponent({
425			values,
426			period,
427			harmonics,
428		}: {
429			values: number[];
430			period: number;
431			harmonics: number;
432		}): number[] {
433			const n = values.length;
434			if (n < period) {
435				return new Array(n).fill(0) as number[];
436			}
437	
438			try {
439				const coefficients = MathematicalFunctions.fourierCoefficients({
440					values,
441					period,
442					harmonics,
443					precision: null,
444				});
445	
446				const seasonal = MathematicalFunctions.reconstructFourierSeries({
447					period,
448					harmonics,
449					a: coefficients.a,
450					b: coefficients.b,
451					length: n,
452				});
453	
454				return seasonal;
455			} catch (error) {
456				this.logger.error(
457					`Error extending seasonal component: ${(error as Error).message}`,
458					(error as Error).stack,
459				);
460				return values.map((_, index) => {
461					const cyclePosition = index % Math.max(1, Math.floor(period));
462					const seasonalIndex = Math.min(cyclePosition, values.length - 1);
463					return values[seasonalIndex] ? values[seasonalIndex] * 0.1 : 0;
464				});
465			}
466		}
