514		private generateDateRange(startDate: string, endDate: string, count: number): string[] {
515			const start = new Date(startDate);
516			const end = new Date(endDate);
517			const totalDays =
518				Math.floor((end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24)) + 1;
519			const step = totalDays / count;
520	
521			const dates: string[] = [];
522			for (let i = 0; i < count; i++) {
523				const currentDate = new Date(start.getTime() + i * step * 24 * 60 * 60 * 1000);
524				const dateArr = currentDate.toISOString().split('T') as [string, string];
525				dates.push(dateArr[0]);
526			}
527			return dates;
528		}
