646		private extendSeasonalComponent(
647			component: number[],
648			period: number,
649			harmonics: number,
650			historicalLength: number,
651			forecastDates: string[],
652			endDate: string,
653		): number[] {
654			if (component.length === 0) return Array(forecastDates.length).fill(0) as number[];
655	
656			try {
657				const coefficients = MathematicalFunctions.fourierCoefficients({
658					values: component,
659					period,
660					harmonics,
661					precision: null,
662				});
663	
664				const forecastValues: number[] = [];
665				const endDateObj = new Date(endDate);
666	
667				for (const forecastDate of forecastDates) {
668					const forecastDateObj = new Date(forecastDate);
669	
670					const daysDiff = Math.floor(
671						(forecastDateObj.getTime() - endDateObj.getTime()) / (1000 * 60 * 60 * 24),
672					);
673	
674					const cyclePosition = (historicalLength + daysDiff) % period;
675					const singlePointSeries = MathematicalFunctions.reconstructFourierSeries({
676						period,
677						harmonics,
678						a: coefficients.a,
679						b: coefficients.b,
680						length: Math.ceil(cyclePosition) + 1,
681						a0: 0,
682					});
683	
684					const seasonalValue = singlePointSeries[Math.floor(cyclePosition)] ?? 0;
685					forecastValues.push(seasonalValue);
686				}
687	
688				return forecastValues;
689			} catch (error) {
690				this.logger.error(
691					`Error extending seasonal component: ${(error as Error).message}`,
692					(error as Error).stack,
693				);
694				return forecastDates.map((forecastDate) => {
695					const endDateObj = new Date(endDate);
696					const forecastDateObj = new Date(forecastDate);
697					const daysDiff = Math.floor(
698						(forecastDateObj.getTime() - endDateObj.getTime()) / (1000 * 60 * 60 * 24),
699					);
700					const flooredPeriod = Math.max(1, Math.floor(period));
